input.content:
extends Node

signal coin_changed(new_count: int)

var count: int = 0

func _ready() -> void:
	load()

func _notification(what: int) -> void:
	if what == NOTIFICATION_WM_CLOSE_REQUEST or what == NOTIFICATION_PREDELETE:
		save()

func add_coin() -> void:
	count += 1
	coin_changed.emit(count)

func get_count() -> int:
	return count

func save() -> void:
	var file = FileAccess.open("user://save.json", FileAccess.WRITE)
	if file:
		var data = {
			"count": count
		}
		var json_string = JSON.stringify(data)
		file.store_string(json_string)
		file.close()

func load() -> void:
	if FileAccess.file_exists("user://save.json"):
		var file = FileAccess.open("user://save.json", FileAccess.READ)
		if file:
			var json_string = file.get_as_text()
			file.close()
			var data = JSON.parse_string(json_string)
			if data is Dictionary and data.has("count"):
				count = int(data["count"])
	coin_changed.emit(count)

extends CharacterBody2D

@export var speed: float = 300.0

func _physics_process(_delta: float) -> void:
	var input_direction := Vector2(
		Input.get_axis("ui_left", "ui_right"),
		Input.get_axis("ui_up", "ui_down")
	)

	if input_direction != Vector2.ZERO:
		input_direction = input_direction.normalized()

	velocity = input_direction * speed
	move_and_slide()

extends Area2D

signal collected

func _ready() -> void:
	body_entered.connect(_on_body_entered)

func _on_body_entered(body: Node2D) -> void:
	if body.name == "Player" or body is CharacterBody2D:
		collected.emit()
		Inventory.add_coin()
		queue_free()

extends CanvasLayer

@onready var coin_label: Label = $Label

func _ready() -> void:
	_update_label(Inventory.get_count())
	Inventory.coin_changed.connect(_update_label)

func _update_label(new_count: int) -> void:
	coin_label.text = "Coins: " + str(new_count)

